      if (ch === "'" || ch === '"') {
        quote = ch;
        buf += ch;
        continue;
      }
      if (ch === "\\" && i + 1 < cmd.length) {
        buf += ch + cmd[++i];
        continue;
      }
      if (ch === ";") {
        parts.push(buf);
        buf = "";
        continue;
